import React, { useState } from 'react';
import { db } from '../firebase';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { ArrowLeft, Upload, Link as LinkIcon, Image as ImageIcon, CheckCircle } from 'lucide-react';

function AddProject({ onNavigate }) {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [category, setCategory] = useState('Web App');
  const [liveDemoUrl, setLiveDemoUrl] = useState(''); // 🆕 New Live URL State
  const [imageBase64, setImageBase64] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  const currentUser = JSON.parse(localStorage.getItem('user_info')) || { name: 'Unknown', email: 'Unknown' };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (file.size > 1048576) {
      setErrorMsg("Image must be less than 1MB.");
      return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
      setImageBase64(reader.result);
      setErrorMsg('');
    };
    reader.readAsDataURL(file);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!title || !description || !imageBase64) {
      setErrorMsg("Title, description, and image are required.");
      return;
    }

    setIsSubmitting(true);
    try {
      await addDoc(collection(db, "projects"), {
        title,
        description,
        category,
        liveDemoUrl, // 🆕 Saving URL to Database
        imageUrl: imageBase64,
        authorName: currentUser.name,
        authorEmail: currentUser.email,
        status: 'Pending',
        createdAt: serverTimestamp(),
        views: 0
      });

      setSuccess(true);
      setTimeout(() => onNavigate('home'), 2000);
    } catch (error) {
      console.error("Error adding document: ", error);
      setErrorMsg("Failed to upload project. Check connection.");
      setIsSubmitting(false);
    }
  };

  if (success) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center p-6 text-white font-sans">
        <div className="bg-white/5 border border-white/10 p-10 rounded-3xl backdrop-blur-xl text-center shadow-2xl animate-fade-in-up max-w-md w-full">
          <CheckCircle className="w-20 h-20 text-green-400 mx-auto mb-6" />
          <h2 className="text-3xl font-bold mb-3 text-white">Project Submitted!</h2>
          <p className="text-gray-400 mb-6">Your project is now waiting for faculty approval.</p>
          <div className="w-full bg-white/10 rounded-full h-1.5 overflow-hidden">
            <div className="bg-green-400 h-1.5 rounded-full animate-progress"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-gray-100 font-sans pb-12">
      {/* 🎨 Premium Header */}
      <div className="bg-black/50 backdrop-blur-xl border-b border-white/10 sticky top-0 z-40">
        <div className="max-w-3xl mx-auto px-6 py-4 flex items-center">
          <button onClick={() => onNavigate('home')} className="mr-4 p-2 rounded-full hover:bg-white/10 transition-colors text-gray-400 hover:text-white">
            <ArrowLeft className="w-6 h-6" />
          </button>
          <div>
            <h1 className="text-2xl font-bold text-white">Upload Project</h1>
            <p className="text-xs text-gray-400">Share your innovation with the campus</p>
          </div>
        </div>
      </div>

      <div className="max-w-3xl mx-auto px-6 mt-8">
        <form onSubmit={handleSubmit} className="bg-white/5 border border-white/10 rounded-[2rem] p-8 backdrop-blur-md shadow-2xl">
          
          {errorMsg && (
            <div className="bg-red-500/10 border border-red-500/30 text-red-400 p-4 rounded-xl mb-6 text-sm font-medium text-center">
              {errorMsg}
            </div>
          )}

          <div className="space-y-6">
            {/* Title */}
            <div>
              <label className="block text-sm font-semibold text-gray-300 mb-2">Project Title</label>
              <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="e.g. AI Attendance System" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all" required />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Category */}
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-2">Category</label>
                <select value={category} onChange={(e) => setCategory(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white outline-none focus:border-indigo-500 appearance-none transition-all">
                  <option className="bg-gray-900">Web App</option>
                  <option className="bg-gray-900">Mobile App</option>
                  <option className="bg-gray-900">Game</option>
                  <option className="bg-gray-900">AI / ML</option>
                  <option className="bg-gray-900">IoT / Hardware</option>
                </select>
              </div>

              {/* 🆕 Live URL Field */}
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-2 flex items-center gap-2">
                  <LinkIcon className="w-4 h-4 text-gray-500" /> Live Demo URL <span className="text-gray-600 font-normal">(Optional)</span>
                </label>
                <input type="url" value={liveDemoUrl} onChange={(e) => setLiveDemoUrl(e.target.value)} placeholder="https://my-app.vercel.app" className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white outline-none focus:border-indigo-500 transition-all placeholder-gray-600" />
              </div>
            </div>

            {/* Description */}
            <div>
              <label className="block text-sm font-semibold text-gray-300 mb-2">Description</label>
              <textarea value={description} onChange={(e) => setDescription(e.target.value)} rows="4" placeholder="Briefly explain what your project does..." className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-white outline-none focus:border-indigo-500 transition-all resize-none" required></textarea>
            </div>

            {/* Image Upload Area */}
            <div>
              <label className="block text-sm font-semibold text-gray-300 mb-2">Cover Image (Max 1MB)</label>
              <div className="relative group border-2 border-dashed border-white/20 rounded-2xl p-8 text-center hover:border-indigo-500/50 hover:bg-white/5 transition-all cursor-pointer bg-black/20">
                <input type="file" accept="image/*" onChange={handleImageUpload} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" required />
                {imageBase64 ? (
                  <div className="flex flex-col items-center">
                    <img src={imageBase64} alt="Preview" className="h-32 object-cover rounded-lg mb-3 shadow-lg border border-white/10" />
                    <span className="text-sm text-green-400 font-medium">Image attached. Click to change.</span>
                  </div>
                ) : (
                  <div className="flex flex-col items-center text-gray-400 group-hover:text-indigo-300 transition-colors">
                    <ImageIcon className="w-10 h-10 mb-3" />
                    <span className="font-medium">Drag & drop or click to browse</span>
                  </div>
                )}
              </div>
            </div>

            {/* Submit Button */}
            <div className="pt-4">
              <button type="submit" disabled={isSubmitting} className={`w-full py-4 rounded-xl font-bold text-lg flex justify-center items-center gap-2 transition-all shadow-lg ${isSubmitting ? 'bg-gray-700 text-gray-400 cursor-not-allowed' : 'bg-indigo-600 text-white hover:bg-indigo-500 hover:shadow-[0_0_20px_rgba(79,70,229,0.4)]'}`}>
                {isSubmitting ? <span className="animate-pulse">Uploading...</span> : <><Upload className="w-5 h-5" /> Publish to Repository</>}
              </button>
            </div>

          </div>
        </form>
      </div>
    </div>
  );
}

export default AddProject;
